    /// <summary>
    /// Maximum number of sentences in the summary (default 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface ISummarizationService
{
    string Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word-frequency relevance
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","after",
        "above","below","not","no","nor","so","if","then","than","too","very",
        "just","also","where","when","how","what","which","who","whom"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i); // preserve original order

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var raw = SentenceBoundary().Split(text.Trim());
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var scored = new List<(int Index, double Score)>(sentences.Count);

        for (var i = 0; i < sentences.Count; i++)
        {
            var words = TokenizeWords(sentences[i]);
            if (words.Length == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => !StopWords.Contains(w) && w.Length >= 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w) / (double)maxFreq);

            // Normalise by word count to avoid favouring very long sentences.
            scored.Add((i, score / words.Length));
        }

        return scored;
    }

    private static string[] TokenizeWords(string sentence) =>
        WordToken().Matches(sentence)
            .Select(m => m.Value)
            .ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly ISummarizationService _summarizationService;

    public SummarizeController(ISummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizationService.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

